import hashlib
import json
import os
import subprocess
import sys
from pathlib import Path
from typing import Dict, List, Optional, Set

class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.pyproject_file = self.project_root / "pyproject.toml"
        
    def generate_requirements_txt(self, output_file: Optional[str] = None) -> None:
        """Generate requirements.txt with hashes using pip-compile."""
        if output_file is None:
            output_file = str(self.requirements_file)
            
        try:
            subprocess.run([
                sys.executable, "-m", "pip", "install", "pip-tools"
            ], check=True, capture_output=True)
            
            subprocess.run([
                sys.executable, "-m", "piptools", "compile", 
                "--generate-hashes", "--output-file", output_file,
                "pyproject.toml"
            ], check=True, capture_output=True)
            
            print(f"Generated {output_file} with hashes")
        except subprocess.CalledProcessError as e:
            print(f"Error generating requirements.txt: {e}")
            raise
            
    def update_requirements_txt(self, output_file: Optional[str] = None) -> None:
        """Update requirements.txt with latest versions."""
        if output_file is None:
            output_file = str(self.requirements_file)
            
        try:
            subprocess.run([
                sys.executable, "-m", "piptools", "compile", 
                "--upgrade", "--generate-hashes", "--output-file", output_file,
                "pyproject.toml"
            ], check=True, capture_output=True)
            
            print(f"Updated {output_file}")
        except subprocess.CalledProcessError as e:
            print(f"Error updating requirements.txt: {e}")
            raise
            
    def verify_requirements_integrity(self) -> bool:
        """Verify integrity of requirements.txt using hashes."""
        if not self.requirements_file.exists():
            print("requirements.txt not found")
            return False
            
        try:
            with open(self.requirements_file, 'r') as f:
                lines = f.readlines()
                
            for line in lines:
                if line.strip() and not line.startswith('#'):
                    if '--hash' in line:
                        # Verify hash integrity
                        hash_part = line.split('--hash=')[1].split()[0]
                        if not self._validate_hash_format(hash_part):
                            print(f"Invalid hash format in: {line.strip()}")
                            return False
                            
            print("Requirements.txt integrity check passed")
            return True
            
        except Exception as e:
            print(f"Error verifying requirements.txt: {e}")
            return False
            
    def _validate_hash_format(self, hash_value: str) -> bool:
        """Validate hash format (sha256, sha384, sha512)."""
        if not hash_value:
            return False
            
        hash_type = hash_value.split(':')[0]
        hash_content = hash_value.split(':')[1]
        
        if hash_type not in ['sha256', 'sha384', 'sha512']:
            return False
            
        try:
            if hash_type == 'sha256':
                return len(hash_content) == 64 and all(c in '0123456789abcdef' for c in hash_content)
            elif hash_type == 'sha384':
                return len(hash_content) == 96 and all(c in '0123456789abcdef' for c in hash_content)
            elif hash_type == 'sha512':
                return len(hash_content) == 128 and all(c in '0123456789abcdef' for c in hash_content)
        except Exception:
            return False
            
        return False
        
    def generate_poetry_lock(self) -> None:
        """Generate poetry.lock file."""
        try:
            subprocess.run([
                "poetry", "lock", "--no-update"
            ], check=True, capture_output=True, cwd=self.project_root)
            
            print("Generated poetry.lock")
        except subprocess.CalledProcessError as e:
            print(f"Error generating poetry.lock: {e}")
            raise
            
    def update_poetry_lock(self) -> None:
        """Update poetry.lock with latest versions."""
        try:
            subprocess.run([
                "poetry", "lock", "--update"
            ], check=True, capture_output=True, cwd=self.project_root)
            
            print("Updated poetry.lock")
        except subprocess.CalledProcessError as e:
            print(f"Error updating poetry.lock: {e}")
            raise
            
    def verify_poetry_lock_integrity(self) -> bool:
        """Verify poetry.lock integrity."""
        if not self.poetry_lock_file.exists():
            print("poetry.lock not found")
            return False
            
        try:
            with open(self.poetry_lock_file, 'r') as f:
                content = f.read()
                
            # Basic integrity check
            if '[metadata]' not in content:
                print("Invalid poetry.lock format")
                return False
                
            print("poetry.lock integrity check passed")
            return True
            
        except Exception as e:
            print(f"Error verifying poetry.lock: {e}")
            return False
            
    def sync_dependencies(self, use_poetry: bool = False) -> None:
        """Install dependencies from lock file."""
        try:
            if use_poetry:
                subprocess.run([
                    "poetry", "install", "--no-root"
                ], check=True, capture_output=True, cwd=self.project_root)
            else:
                subprocess.run([
                    sys.executable, "-m", "pip", "install", "--no-deps", 
                    "-r", str(self.requirements_file)
                ], check=True, capture_output=True)
                
            print("Dependencies synced successfully")
        except subprocess.CalledProcessError as e:
            print(f"Error syncing dependencies: {e}")
            raise
            
    def get_dependency_info(self) -> Dict:
        """Get dependency information from lock files."""
        info = {
            "requirements": {},
            "poetry": {}
        }
        
        if self.requirements_file.exists():
            try:
                with open(self.requirements_file, 'r') as f:
                    lines = f.readlines()
                    
                for line in lines:
                    if line.strip() and not line.startswith('#') and not line.startswith('--hash'):
                        if '==' in line:
                            package, version = line.split('==')
                            info["requirements"][package.strip()] = version.strip()
            except Exception as e:
                print(f"Error reading requirements.txt: {e}")
                
        if self.poetry_lock_file.exists():
            try:
                with open(self.poetry_lock_file, 'r') as f:
                    content = f.read()
                    
                # Simple parsing for version info
                lines = content.split('\n')
                current_package = None
                for line in lines:
                    if line.startswith('[[package]]'):
                        current_package = None
                    elif line.startswith('name = ') and current_package is None:
                        current_package = line.split(' = ')[1].strip('"')
                    elif line.startswith('version = ') and current_package:
                        version = line.split(' = ')[1].strip('"')
                        info["poetry"][current_package] = version
            except Exception as e:
                print(f"Error reading poetry.lock: {e}")
                
        return info
        
    def create_dependency_manifest(self, output_file: str = "dependency_manifest.json") -> None:
        """Create a manifest file with dependency information."""
        manifest = {
            "generated_at": str(subprocess.run(["date"], capture_output=True, text=True).stdout.strip()),
            "dependencies": self.get_dependency_info(),
            "checksums": self._generate_checksums()
        }
        
        with open(output_file, 'w') as f:
            json.dump(manifest, f, indent=2)
            
        print(f"Created dependency manifest: {output_file}")
        
    def _generate_checksums(self) -> Dict:
        """Generate checksums for lock files."""
        checksums = {}
        
        if self.requirements_file.exists():
            checksums["requirements.txt"] = self._calculate_file_hash(self.requirements_file)
            
        if self.poetry_lock_file.exists():
            checksums["poetry.lock"] = self._calculate_file_hash(self.poetry_lock_file)
            
        return checksums
        
    def _calculate_file_hash(self, file_path: Path) -> str:
        """Calculate SHA256 hash of a file."""
        hash_sha256 = hashlib.sha256()
        try:
            with open(file_path, "rb") as f:
                for chunk in iter(lambda: f.read(4096), b""):
                    hash_sha256.update(chunk)
            return hash_sha256.hexdigest()
        except Exception:
            return ""

